use tokio;

pub async fn race_first<T: Send + 'static>(
    futures: Vec<tokio::task::JoinHandle<T>>,
) -> Result<T, tokio::task::JoinError> {
    let (result, _, remaining) = futures::future::select_all(futures).await;
    for handle in remaining {
        handle.abort();
    }
    result
}

