I[T] ~ DoublyLinked[T] {
    +f new() -> Self {
        DoublyLinked @{ head: Link.None, tail: Link.None, len: 0 }
    }

    +f push_front(&!self, val: T) {
        v new_node = $RefCell.new(RefCell.new(Node @{
            value: val,
            prev: Link.None,
            next: self.head.clone(),
        }));
        ? v old_head = self.head.take() {
            old_head.borrow_mut().prev = Link.Some(new_node.clone());
        } : {
            self.tail = Link.Some(new_node.clone());
        }
        self.head = Link.Some(new_node);
        self.len += 1;
    }

    +f push_back(&!self, val: T) {
        v new_node = $RefCell.new(RefCell.new(Node @{
            value: val,
            prev: self.tail.clone(),
            next: Link.None,
        }));
        ? v old_tail = self.tail.take() {
            old_tail.borrow_mut().next = Link.Some(new_node.clone());
        } : {
            self.head = Link.Some(new_node.clone());
        }
        self.tail = Link.Some(new_node);
        self.len += 1;
    }

    +f len(&self) -> usize { self.len }
}

