@d(Debug, Clone)
+S CrawlResult {
    +url: s,
    +depth: u32,
    +links: [s]~,
}

+af crawl(
    start_url: s,
    max_depth: u32,
    max_concurrent: usize,
) -> [CrawlResult]~ / io + net {
    v visited = @Mutex.new(Mutex.new({s}.new()));
    v results = @Mutex.new(Mutex.new([CrawlResult]~.new()));
    v sem = @Semaphore.new(max_concurrent);

    crawl_recursive(start_url, 0, max_depth, &visited, &results, &sem).await;

    @Mutex.try_unwrap(results).unwrap().into_inner().unwrap()
}

af crawl_recursive(
    url: s,
    depth: u32,
    max_depth: u32,
    visited: &@Mutex[{s}],
    results: &@Mutex[[CrawlResult]~],
    sem: &@Semaphore,
) / io + net {
    ? depth > max_depth { ret }

    {
        m guard = visited.lock().unwrap();
        ? !guard.insert(url.clone()) { ret }
    }

    v _permit = sem.acquire().await.unwrap();
    v links = fetch_and_parse(&url).await;

    v result = CrawlResult @{ url: url.clone(), depth, links: links.clone() };
    results.lock().unwrap().push(result);

    v handles: [_]~ = links.into_iter().map(|link| {
        v visited = visited.clone();
        v results = results.clone();
        v sem = sem.clone();
        tokio.spawn(af {
            crawl_recursive(link, depth + 1, max_depth, &visited, &results, &sem).await;
        })
    }).collect();

    @ h ~ handles { v _ = h.await; }
}

af fetch_and_parse(url: &s) -> [s]~ / io + net {
    // Fetch URL and extract links
    [s]~.new()
}
